#!/usr/bin/env dotnet
#:include *.cs
#:include Models/*.cs
#:exclude Scratch.cs

var person = new Person("Ada", "Lovelace");
Console.WriteLine(NameHelper.ToUpper(person));

static class NameHelper
{
    public static string ToUpper(Person person) =>
        $"{person.FirstName} {person.LastName}".ToUpperInvariant();
}

